const query = $.input.searchQuery || $.input.question;
const hasDirectUrl = !!$.input.documentUrl;
return { query, hasDirectUrl };

if ($.input.documentUrl) {
  return { url: $.input.documentUrl, source: 'direct' };
}
const results = ($.steps.searchDocs && $.steps.searchDocs.response && $.steps.searchDocs.response.results) || [];
if (results.length === 0) {
  return { url: null, source: 'none', error: 'No documents found' };
}
return { url: results[0].url, source: 'exa_search', allResults: results.map((r, i) => ({ index: i+1, title: r.title || '', url: r.url, snippet: (r.text || '').slice(0, 300) })) };

const scrapeResp = ($.steps.scrapeDoc && $.steps.scrapeDoc.response && $.steps.scrapeDoc.response.data) || {};
const primaryContent = scrapeResp.markdown || '';
const primaryUrl = $.steps.resolveUrl.output.url || '';

const searchResults = $.steps.resolveUrl.output.allResults || [];

let context = 'PRIMARY DOCUMENT:\n';
context += 'URL: ' + primaryUrl + '\n';
context += 'Content:\n' + primaryContent.slice(0, 6000) + '\n\n';

if (searchResults.length > 1) {
  context += 'ADDITIONAL SEARCH RESULTS:\n';
  searchResults.slice(1).forEach((r, i) => {
    context += (i + 2) + '. ' + r.title + ' (' + r.url + ')\n';
    context += '   ' + r.snippet + '\n\n';
  });
}

return { context, primaryUrl, hasContent: primaryContent.length > 0, sourceCount: searchResults.length || 1 };

const question = $.input.question;
const context = $.steps.compileContext.output.context;

let prompt = 'You are a document analysis assistant. Answer the user question based ONLY on the provided document content. You MUST cite your sources by quoting the exact text you used to form your answer.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'DOCUMENT CONTENT:\n' + context + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer the question thoroughly using information from the document\n';
prompt += '- Include direct quotes from the source text as citations\n';
prompt += '- If the document does not contain enough information to answer, say so clearly\n';
prompt += '- Attribute each piece of information to its source URL\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "your detailed answer to the question",\n';
prompt += '  "citations": [\n';
prompt += '    { "quote": "exact text quoted from the document", "sourceUrl": "URL where this was found", "relevance": "why this quote supports the answer" }\n';
prompt += '  ],\n';
prompt += '  "confidence": "high/medium/low",\n';
prompt += '  "summary": "one-sentence summary of the answer"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, citations: [], confidence: 'low', summary: 'See raw answer' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const primaryUrl = $.steps.compileContext.output.primaryUrl || '';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Document Q&A', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + answerText } });

if (ai.citations && ai.citations.length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Sources & Citations:*' } });
  ai.citations.slice(0, 5).forEach((c, i) => {
    let citText = '>' + (i + 1) + '. _"' + (c.quote || '').slice(0, 300) + '"_\n';
    if (c.sourceUrl) citText += '   <' + c.sourceUrl + '|Source>';
    if (c.relevance) citText += ' - ' + c.relevance;
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: citText } });
  });
}

blocks.push({ type: 'divider' });
const confEmoji = ai.confidence === 'high' ? 'large_green_circle' : ai.confidence === 'medium' ? 'large_yellow_circle' : 'red_circle';
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':' + confEmoji + ': Confidence: ' + (ai.confidence || 'unknown') + ' | Source: <' + primaryUrl + '|Document>' }] });

const fallbackText = 'Document Q&A: ' + (ai.summary || question);
return { blocks, fallbackText };
